import NavbarGestionSalas from "../components/NavbarGestionSalas";
import "../styles/AgregarRecurso.css";

function AgregarRecurso() {
  return (
    <div className="recursoContainer">
      <NavbarGestionSalas />

      {/* CONTENIDO */}
      <div className="recursoContent">

        {/* IZQUIERDA */}
        <div className="recursoLeftPanel">
          <h2>Recursos</h2>
        </div>

        {/* DERECHA */}
        <div className="recursoRightPanel">

          <div className="recursoCard">
            <p><strong>Recurso No° 1</strong></p>
            <p>Nombre: Oficina Dirección</p>
          </div>

          <div className="recursoCard">
            <p><strong>Recurso No° 2</strong></p>
            <p>Nombre: Salón Aulas 4</p>
          </div>

        </div>

      </div>

      {/* FOOTER */}
      <div className="recursoFooter">

        <div className="recursoButtons">
          <button className="recursoAddBtn">Agregar</button>
          <button className="recursoDeleteBtn">Eliminar</button>
        </div>

        <button className="recursoNextBtn">→</button>

      </div>
    </div>
  );
}

export default AgregarRecurso;
